import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as c,c as o,e as d}from"./app-be253e4c.js";const a={},s=d(`<h1 id="split命令" tabindex="-1"><a class="header-anchor" href="#split命令" aria-hidden="true">#</a> split命令</h1><p><code>split</code>命令用于将大文件分割成较小的文件，在默认情况下将按照每<code>1000</code>行切割成一个小文件。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">split</span> <span class="token punctuation">[</span>OPTION<span class="token punctuation">]</span><span class="token punctuation">..</span>. <span class="token punctuation">[</span>FILE <span class="token punctuation">[</span>PREFIX<span class="token punctuation">]</span><span class="token punctuation">]</span>
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>-a, --suffix-length=N</code>: 使用长度为<code>N</code>的后缀，默认为<code>2</code>。</li><li><code>--additional-suffix=SUFFIX</code>: 将额外的<code>SUFFIX</code>插入文件名。</li><li><code>-b, --bytes=SIZE</code>: 每个输出文件放置<code>SIZE</code>字节，即指定每多少字节切成一个小文件。</li><li><code>-C, --line-bytes=SIZE</code>: 每个输出文件最多放入<code>SIZE</code>个字节行，与参数<code>-b</code>相似，但是在切割时将尽量维持每行的完整性。</li><li><code>-d</code>: 使用数字后缀而不是字母。</li><li><code>--numeric-suffixes[=FROM]</code>: 与<code>-d</code>相同，但允许设置起始值。</li><li><code>-e, --elide-empty-files</code>: 不使用<code>-n</code>生成空的输出文件。</li><li><code>--filter=COMMAND</code>: 写入<code>shell</code>命令<code>COMMAND</code>，文件名是<code>$FILE</code>。</li><li><code>-l, --lines=NUMBER</code>: 每个输出文件放入<code>NUMBER</code>行。</li><li><code>-n, --number=CHUNKS</code>: 生成<code>CHUNKS</code>输出文件，<code>CHUNKS</code>可以取的值有，<code>N</code>:根据输入大小分为<code>N</code>个文件，<code>K/N</code>:将<code>N</code>的第<code>K</code>个输出到标准输出，<code>l/N</code>: 分割成<code>N</code>个文件，不分割行，<code>l/K/N</code>:输出<code>K</code>的第<code>N</code>到标准输出，而不分割线，<code>r/N</code>:类似于<code>l</code>，但同样使用循环分布<code>r/K/N</code>，但仅将<code>N</code>的第<code>K</code>个输出到标准输出。</li><li><code>-t, --separator=SEP</code>: 使用<code>SEP</code>代替换行符作为记录分隔符，<code>\\0</code>即<code>0</code>指定<code>NUL</code>字符。</li><li><code>-u, --unbuffered</code>: 立即使用<code>-n r/...</code>将输入复制到输出。</li><li><code>--verbose</code>: 在打开每个输出文件之前，输出详细的信息。</li><li><code>--help</code>: 输出帮助信息。</li><li><code>--version</code>: 输出版本信息。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>将文件<code>tmp/file.txt</code>分<code>N</code>个独立的文件，分别为<code>newaa</code>、<code>newab</code>、<code>newac</code>、<code>...</code>，每个文件包含<code>2</code>个字节的数据。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">split</span> <span class="token parameter variable">-b</span> <span class="token number">2</span> /tmp/file.txt new
</code></pre></div><p>将文件<code>tmp/file.txt</code>分<code>N</code>个独立的文件，分别为<code>newaa</code>、<code>newab</code>、<code>newac</code>、<code>...</code>，每个文件包含<code>2</code>行数据。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code> <span class="token function">split</span> <span class="token parameter variable">-l</span> <span class="token number">2</span> /tmp/file.txt new
</code></pre></div><p>将文件<code>tmp/file.txt</code>分<code>N</code>个独立的文件，以数字作为后缀，每个文件包含<code>2</code>行数据。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">split</span> <span class="token parameter variable">-d</span> <span class="token parameter variable">-l</span> <span class="token number">2</span> /tmp/file.txt new
</code></pre></div>`,13),n=[s];function l(t,i){return c(),o("div",null,n)}const u=e(a,[["render",l],["__file","split.html.vue"]]);export{u as default};
